 1	import React, { FC, useCallback } from 'react';
 2	
 3	import { TemplateModel, V1Template } from '@kubevirt-ui/kubevirt-api/console';
 4	import SidebarEditor from '@kubevirt-utils/components/SidebarEditor/SidebarEditor';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { k8sUpdate } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Grid, GridItem, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
 8	
 9	import useEditTemplateAccessReview from '../../hooks/useIsTemplateEditable';
10	
11	import TemplateSchedulingLeftGrid from './components/TemplateSchedulingLeftGrid';
12	import TemplateSchedulingRightGrid from './components/TemplateSchedulingRightGrid';
13	
14	import './TemplateSchedulingTab.scss';
15	
16	type TemplateSchedulingTabProps = {
17	  obj?: V1Template;
18	};
19	
20	const TemplateSchedulingTab: FC<TemplateSchedulingTabProps> = ({ obj: template }) => {
21	  const { isTemplateEditable } = useEditTemplateAccessReview(template);
22	  const { t } = useKubevirtTranslation();
23	
24	  const onSubmitTemplate = useCallback(
25	    (updatedTemplate: V1Template) =>
26	      k8sUpdate({
27	        data: updatedTemplate,
28	        model: TemplateModel,
29	        name: updatedTemplate?.metadata?.name,
30	        ns: updatedTemplate?.metadata?.namespace,
31	      }),
32	    [],
33	  );
34	
35	  return (
36	    <PageSection variant={PageSectionVariants.light}>
37	      <SidebarEditor<V1Template> onResourceUpdate={onSubmitTemplate} resource={template}>
38	        {(resource) => (
39	          <>
40	            <Title headingLevel="h2">{t('Scheduling and resource requirements')}</Title>
41	            <Grid className="margin-top">
42	              <GridItem span={5}>
43	                <TemplateSchedulingLeftGrid editable={isTemplateEditable} template={resource} />
44	              </GridItem>
45	              <GridItem lg={1}></GridItem>
46	              <GridItem span={5}>
47	                <TemplateSchedulingRightGrid editable={isTemplateEditable} template={resource} />
48	              </GridItem>
49	            </Grid>
50	          </>
51	        )}
52	      </SidebarEditor>
53	    </PageSection>
54	  );
55	};
56	
57	export default TemplateSchedulingTab;

